  ('social-worker-moex-01691', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理大師Peter F. Drucker對管理的論述非常豐富，有關他的核心理念，下列敘述何者錯誤？', '["管理應將一切事物化繁為簡", "企業和政府都有人類自然的傾向，無視明顯不適用的事實，對昨日的成功念念不忘", "組織應重視員工，並以顧客為導向", "獲利是組織的重要目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01692', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關學習型組織的敘述，何者錯誤？', '["能引導具體的人力訓練和人力發展措施", "強調組織員工間的學習", "重視組織的效率與個人績效", "挑戰傳統的科層組織"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01693', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理理論中忽略組織中非正式權力結構的影響，過度強調職責與生產力，主要是針對下列那種管 理理論的評述？', '["新管理主義", "古典管理理論", "人群關係學派管理理論", "權變管理理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01694', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Elton Mayo在霍桑（Hawthorne）工廠進行團體態度與反應研究的實驗說明人群關係影響生產力， 下列有關「霍桑實驗」的敘述，何者錯誤？', '["生產的高低是由社會規範所設定而不是生理的能力", "經濟性獎勵會顯著影響人的生產行為", "社會和人際影響是生產力較強的預測因素，甚於與物理環境有關的因素", "工作場域存在多種文化或次文化，若生產力要求最大化，必須同時注意工作場域中個人歸屬感 的需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01695', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '公部門的局處主管參考了當地的納稅人、局處的員工、服務使用者及地方社會福利組織的意見來 訂定績效目標，請問這位局處主管運用「最佳價值」觀點的那項原則？', '["徵詢（consultation）", "競爭（competition）", "挑戰績效（challenging performance）", "比較績效（comparinging performance）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01696', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '實務上常以J. Bradshaw所提出的四個不同但相輔相成的需求觀點為評量（assessment）依據，下 列對於需求觀點與評量方法的配對，何者錯誤？', '["以現有研究資料進行差補外推法可以評量規範性需求", "在社區舉辦公聽會可以評量感受性需求", "針對某區內的所有機構進行服務現況統計分析可以評量表達性需求", "依政策規定之內涵作為方案設計之依據可以視為相對性需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
