  ('social-worker-moex-01698', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以某機構所辦理之「18 歲以下未婚懷孕少女之支持服務方案」為例，下列敘述何者不屬於邏輯 模式方案設計之運作過程（throughputs）的範疇？', '["至小學、國中與高中職學校辦理安全性行為的講座活動", "制定問卷來調查未婚懷孕少女需要那些協助與服務", "設置未婚懷孕少女的諮詢服務專線", "提供未婚懷孕少女陪同就醫服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01699', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '就績效測量、監督與方案評估三者而言，下列有關方案績效測量主要目的之敘述，何者錯誤？', '["績效測量的主要目的是要確認方案是否依原先之設定執行", "績效測量是指持續回報方案的完成進度，特別是方案的輸出、品質及結果", "方案績效報告可作為對利害關係人之責信", "績效測量能夠回答「方案提供了多少產出和服務？」「產品或方案提供的服務品質如何？」「方 案的成本效率及成本功效為何？」等問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01700', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人力資源管理包括晉用、培訓與發展、激勵及維持等措施，下列何者不屬於維持的範疇？', '["確保適當溝通管道的順暢", "提供有效的福利方案", "落實績效評估", "建立安全暨健康的工作環境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
